func main() {
	logger := slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
		Level: slog.LevelInfo,
	}))
	slog.SetDefault(logger)

	if err := run(); err != nil {
		slog.Error("server terminated with error", "error", err)
		os.Exit(1)
	}
}

func run() error {
	// --- Configuration ---
	cfg, err := config.Load()
	if err != nil {
		return fmt.Errorf("configuration: %w", err)
	}

	// Log only safe fields — never log DSN, secrets, or key paths.
	slog.Info("configuration loaded", slog.Any("config", cfg.SafeLogFields()))

	// --- Database ---
	ctx := context.Background()
	pool, err := db.Connect(ctx, cfg.DB.DSN)
	if err != nil {
		return fmt.Errorf("database: %w", err)
	}
	defer pool.Close()
	slog.Info("database connection pool established")

	// --- Migrations ---
	if err := runMigrations(cfg.DB.DSN, cfg.Migrate.Path); err != nil {
		return fmt.Errorf("migrations: %w", err)
	}
	slog.Info("database migrations applied")

	// --- HTTP Server ---
	e := echo.New()
	e.HideBanner = true
	e.HidePort = true

	// Global middleware (applied to all routes).
	e.Use(appmw.RequestID())
	e.Use(echomw.RecoverWithConfig(echomw.RecoverConfig{
		LogErrorFunc: func(c echo.Context, err error, stack []byte) error {
			slog.Error("panic recovered",
				"error", err,
				"request_id", c.Response().Header().Get(echo.HeaderXRequestID),
			)
			return nil
		},
	}))
	e.Use(echomw.LoggerWithConfig(echomw.LoggerConfig{
		// Structured JSON logging — no sensitive query params logged.
		Format: `{"time":"${time_rfc3339}","level":"INFO","request_id":"${id}","method":"${method}","uri":"${uri}","status":${status},"latency_ms":${latency_ms}}` + "\n",
	}))

	// --- Routes ---
	registerRoutes(e, pool)

	// --- Graceful shutdown ---
	serverAddr := cfg.Addr()
	slog.Info("starting HTTP server", "addr", serverAddr)

	go func() {
		if err := e.Start(serverAddr); err != nil && !errors.Is(err, http.ErrServerClosed) {
			slog.Error("HTTP server error", "error", err)
			os.Exit(1)
		}
	}()

	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
	<-quit

	slog.Info("shutdown signal received, draining connections")
	shutdownCtx, cancel := context.WithTimeout(context.Background(), 15*time.Second)
	defer cancel()

	if err := e.Shutdown(shutdownCtx); err != nil {
		return fmt.Errorf("graceful shutdown failed: %w", err)
	}

	slog.Info("server stopped cleanly")
	return nil
}

// registerRoutes wires all HTTP routes to their handlers.
// Business-domain routes are registered here as they are implemented in
// subsequent phases. Each domain group will have its own registration
// function (e.g., readers.RegisterRoutes, holdings.RegisterRoutes).
func registerRoutes(e *echo.Echo, pool *db.Pool) {
	api := e.Group("/api/v1")

	// Liveness — no database check. Safe to call before DB is ready.
	api.GET("/health", health.LiveHandler)

	// Readiness — pings the database. Use this to verify DB connectivity.
	api.GET("/ready", health.ReadyHandler(pool))

	// ---------------------------------------------------------------
	// SCAFFOLD NOTICE: The following domain route groups are registered
	// but not yet implemented. They will return 501 Not Implemented
	// until their respective phases are complete.
	// ---------------------------------------------------------------
	stubGroup(api, "/auth")
	stubGroup(api, "/users")
	stubGroup(api, "/readers")
	stubGroup(api, "/holdings")
	stubGroup(api, "/copies")
	stubGroup(api, "/circulation")
	stubGroup(api, "/stocktake")
	stubGroup(api, "/programs")
	stubGroup(api, "/enrollments")
	stubGroup(api, "/feedback")
	stubGroup(api, "/appeals")
	stubGroup(api, "/moderation")
	stubGroup(api, "/content")
	stubGroup(api, "/imports")
	stubGroup(api, "/exports")
	stubGroup(api, "/reports")
}

// stubGroup registers a catch-all route for a path prefix that returns
// 501 Not Implemented. This makes the scaffold's intention explicit:
// the endpoint group exists in the design but has no implementation yet.
func stubGroup(parent *echo.Group, prefix string) {
	parent.Any(prefix+"*", func(c echo.Context) error {
		return c.JSON(http.StatusNotImplemented, map[string]string{
			"error":  "not_implemented",
			"detail": "this endpoint group is scaffolded but not yet implemented",
			"path":   c.Request().URL.Path,
		})
	})
}

// runMigrations applies pending SQL migrations from the given directory path.
func runMigrations(dsn, migrationsPath string) error {
	return runMigrationsInternal(dsn, migrationsPath)
}
"}

