// Phase 2 will add AuthContext, BrowserRouter, and route definitions here.
//
// SCAFFOLD NOTICE: This component renders a status page only. No business
// features, routing, or authentication are implemented in Phase 1.

const IMPLEMENTED_FEATURES = [
  'Backend project scaffold and configuration loading',
  'PostgreSQL connection pool setup',
  'Database migration runner (golang-migrate)',
  'Health/liveness endpoint: GET /api/v1/health',
  'Readiness endpoint (DB ping): GET /api/v1/ready',
  'Stub 501 responses for all future domain route groups',
  'Frontend project scaffold (React 18 + TypeScript + Vite)',
  'Frontend test infrastructure (Vitest + Testing Library)',
];

const PENDING_FEATURES = [
  'Authentication and session management (Phase 2)',
  'User, role, and RBAC management (Phase 3)',
  'Reader profile management with encryption and field masking (Phase 4)',
  'Holdings and copy-level inventory (Phase 5)',
  'Circulation events (Phase 6)',
  'Stocktake sessions (Phase 7)',
  'Program enrollment with conflict/capacity/eligibility checks (Phase 8)',
  'Feedback, ratings, appeals, arbitration (Phase 9)',
  'Content publishing and moderation (Phase 10)',
  'Bulk import/export with preview and rollback (Phase 11)',
  'Configurable reports and audited exports (Phase 12)',
  'Full frontend UI for all domain modules (Phase 13)',
];

function StatusList({ title, items }: { title: string; items: string[] }) {
  return (
    <section style={{ marginBottom: '2rem' }}>
      <h2 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: '0.5rem' }}>
        {title}
      </h2>
      <ul style={{ paddingLeft: '1.5rem', lineHeight: 1.8 }}>
        {items.map((item) => (
          <li key={item}>{item}</li>
        ))}
      </ul>
    </section>
  );
}

export default function App() {
  return (
    <div
      style={{
        fontFamily: 'system-ui, sans-serif',
        maxWidth: '720px',
        margin: '4rem auto',
        padding: '0 1.5rem',
        color: '#1a1a2e',
      }}
    >
      <h1 style={{ fontSize: '1.5rem', fontWeight: 700, marginBottom: '0.5rem' }}>
        Library Operations &amp; Enrollment Management Suite
      </h1>
      <p
        style={{
          fontSize: '0.875rem',
          background: '#fef3c7',
          border: '1px solid #f59e0b',
          padding: '0.75rem 1rem',
          borderRadius: '4px',
          marginBottom: '2rem',
        }}
      >
        <strong>Phase 1 — Foundation only.</strong> This is the application
        scaffold. No business features are available yet. See the README for the
