{"file_path": "/home/leul/Documents/w2t26/repo/backend/tests/integration/schema_test.go", "content": "// Package integration contains tests that require a live PostgreSQL database.
// Run with: DATABASE_TEST_URL=<dsn> go test ./tests/integration/...
// Or set DATABASE_TEST_URL in backend/.env.
//
// These tests verify:
//  1. All migrations apply cleanly (forward and in the correct order).
//  2. Critical uniqueness constraints are enforced (barcode, reader_number, etc.).
//  3. Critical foreign-key and check constraints are enforced.
//  4. Seed data is present after migration 014.
package integration

import (
	"context"
	"fmt"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"lms/tests/testdb"
)

// TestMigrations_AllTablesPresent verifies that all expected tables exist after
// running all migrations against the test database. This is the migration
// sanity check required by the acceptance rules.
func TestMigrations_AllTablesPresent(t *testing.T) {
	pool := testdb.Open(t)
	defer pool.Close()

	expectedTables := []string{
		"roles", "permissions", "role_permissions",
		"users", "user_roles",
		"sessions", "captcha_challenges",
		"branches", "user_branch_assignments",
		"reader_statuses", "readers",
		"holdings", "copy_statuses", "copies",
		"circulation_events",
		"stocktake_sessions", "stocktake_findings",
		"programs", "program_prerequisites", "enrollment_rules",
		"enrollments", "enrollment_history",
		"governed_content", "moderation_items",
		"feedback_tags", "feedback", "feedback_tag_mappings",
		"appeals", "appeal_arbitrations",
		"import_jobs", "import_rows",
		"export_jobs",
		"audit_events",
		"report_definitions", "report_aggregates",
	}

	for _, table := range expectedTables {
		t.Run("table_exists/"+table, func(t *testing.T) {
			var exists bool
			err := pool.QueryRow(context.Background(),
				`SELECT EXISTS(
					SELECT 1 FROM pg_tables
					WHERE schemaname = 'lms' AND tablename = $1
				)`, table).Scan(&exists)
			require.NoError(t, err)
			assert.True(t, exists, "table lms.%s must exist after migrations", table)
		})
	}
}

// TestConstraint_BarcodeUnique verifies that inserting two copies with the same
// barcode raises a unique constraint violation.
func TestConstraint_BarcodeUnique(t *testing.T) {
	pool := testdb.Open(t)
	defer pool.Close()

	ctx := context.Background()

	// Use seeded branch and a real holding inserted for this test.
	branchID := "bbbbbbbb-0000-0000-0000-000000000001" // MAIN branch from seed

	// Insert a holding to attach copies to.
	var holdingID string
	err := pool.QueryRow(ctx,
		`INSERT INTO lms.holdings (branch_id, title, language)
		 VALUES ($1, 'Test Holding for Barcode Constraint', 'en')
		 RETURNING id`,
		branchID,
	).Scan(&holdingID)
