	defer pool.Close()

	ctx := context.Background()
	branchID := "bbbbbbbb-0000-0000-0000-000000000001"
	barcode := "BARCODE-" + uniqueSuffix()

	tx, err := pool.Begin(ctx)
	require.NoError(t, err)
	defer tx.Rollback(ctx) //nolint:errcheck

	// Insert a holding.
